from collections import deque
import sys
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = (0, 0)
    for i in range(n):
        row = input().strip()
        grid.append(row)
        for j, c in enumerate(row):
            if c == 'L':
                lab = (i, j)

    dirs = [(-1,0),(1,0),(0,-1),(0,1)]

    # Count free neighbors for each cell
    free_neighbors = [[0]*m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            if grid[i][j] == '#':
                continue
            cnt = 0
            for di, dj in dirs:
                ni, nj = i+di, j+dj
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#':
                    cnt += 1
            free_neighbors[i][j] = cnt

    good = [[False]*m for _ in range(n)]
    # not_good_count[i][j] = number of free neighbors that are not yet good
    not_good_count = [row[:] for row in free_neighbors]

    queue = deque()
    li, lj = lab
    good[li][lj] = True
    queue.append((li, lj))

    while queue:
        i, j = queue.popleft()
        for di, dj in dirs:
            ni, nj = i+di, j+dj
            if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] != '#' and not good[ni][nj]:
                not_good_count[ni][nj] -= 1
                if not_good_count[ni][nj] <= 1:
                    good[ni][nj] = True
                    queue.append((ni, nj))

    result = []
    for i in range(n):
        row = list(grid[i])
        for j in range(m):
            if row[j] == '.' and good[i][j]:
                row[j] = '+'
        result.append(''.join(row))
    print('\n'.join(result))

t = int(input())
for _ in range(t):
    solve()

